const response = $input.first().json;
const content = response.content?.[0]?.text || '[]';
let tenders;
try {
  const jsonMatch = content.match(/\[.*\]/s);
  tenders = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{ json: { tenders_found: 0 } }];
}
return tenders.map(t => ({ json: { ...t, source: 'perplexity' } }));
